const app = express();

const UPLOAD_DIR = path.join(__dirname, 'public', 'uploads');
const THUMB_DIR = path.join(UPLOAD_DIR, 'thumbnails');

fs.mkdirSync(UPLOAD_DIR, { recursive: true });
fs.mkdirSync(THUMB_DIR, { recursive: true });

const allowedMimeTypes = new Set([
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/svg+xml',
  'application/pdf',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/zip'
]);

const allowedExtensions = new Set([
  '.jpg',
  '.jpeg',
  '.png',
  '.gif',
  '.svg',
  '.pdf',
  '.doc',
  '.docx',
  '.zip'
]);

function getExtension(file) {
  return path.extname(file.originalname || '').toLowerCase();
}

function isAllowedFile(file) {
  return allowedMimeTypes.has(file.mimetype) && allowedExtensions.has(getExtension(file));
}

function safeName(originalname) {
  const ext = path.extname(originalname || '').toLowerCase();
  const base = path.basename(originalname || '', ext).replace(/[^a-z0-9-_]+/gi, '_').replace(/^_+|_+$/g, '');
  const unique = `${Date.now()}-${crypto.randomBytes(8).toString('hex')}`;
  return `${base || 'file'}-${unique}${ext}`;
}

const storage = multer.diskStorage({
  destination: (req, file, cb) => cb(null, UPLOAD_DIR),
  filename: (req, file, cb) => cb(null, safeName(file.originalname))
});

const upload = multer({
  storage,
  fileFilter: (req, file, cb) => {
    if (isAllowedFile(file)) return cb(null, true);
    cb(new Error('Unsupported file type'));
  },
  limits: {
    fileSize: (req) => {
      const isEnterprise = String(req.headers['x-user-tier'] || '').toLowerCase() === 'enterprise';
      return isEnterprise ? Infinity : 25 * 1024 * 1024;
    }
  }
});

function fileSizeLimitMiddleware(req, res, next) {
  const isEnterprise = String(req.headers['x-user-tier'] || '').toLowerCase() === 'enterprise';
  req.fileSizeLimit = isEnterprise ? Infinity : 25 * 1024 * 1024;
  next();
}

function dynamicUpload(req, res, next) {
  const isEnterprise = String(req.headers['x-user-tier'] || '').toLowerCase() === 'enterprise';
  const uploader = multer({
    storage,
    fileFilter: (r, file, cb) => {
      if (isAllowedFile(file)) return cb(null, true);
      cb(new Error('Unsupported file type'));
    },
    limits: {
      fileSize: isEnterprise ? Infinity : 25 * 1024 * 1024
    }
  }).single('file');
  uploader(req, res, next);
}

async function generateThumbnail(sourcePath, filename) {
  const ext = path.extname(filename).toLowerCase();
  const thumbName = `${path.basename(filename, ext)}.thumb.jpg`;
  const thumbPath = path.join(THUMB_DIR, thumbName);

  if (ext === '.svg') {
    await sharp(Buffer.from(fs.readFileSync(sourcePath))).resize(300, 300, { fit: 'inside' }).jpeg({ quality: 85 }).toFile(thumbPath);
    return thumbPath;
  }

  await sharp(sourcePath)
    .resize(300, 300, { fit: 'inside', withoutEnlargement: true })
    .jpeg({ quality: 85 })
    .toFile(thumbPath);

  return thumbPath;
}

